bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting download from %s", url.c_str());

    // Find the assets partition
    const esp_partition_t* partition = esp_partition_find_first(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, "assets");
    if (partition == nullptr) {
        ESP_LOGE(TAG, "No assets partition found");
        return false;
    }

    // Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.timeout_ms = 30000; // 30 second timeout

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Open HTTP connection
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_fetch_headers(client);
    if (content_length < 0) {
        ESP_LOGE(TAG, "Failed to fetch headers");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Content length: %d bytes", content_length);
    ESP_LOGI(TAG, "Partition size: %d bytes", partition->size);

    // Check if content fits in partition
    if (content_length > (int)partition->size) {
        ESP_LOGE(TAG, "Content size (%d) exceeds partition size (%d)", content_length, partition->size);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase the partition before writing
    ESP_LOGI(TAG, "Erasing partition...");
    err = esp_partition_erase_range(partition, 0, partition->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Download and write data
    const size_t buffer_size = 4096;
    uint8_t* buffer = (uint8_t*)malloc(buffer_size);
    if (buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate download buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    size_t offset = 0;
    auto start_time = esp_timer_get_time();
    auto last_progress_time = start_time;
    int last_progress = 0;

    while (total_written < content_length) {
        int read_len = esp_http_client_read(client, (char*)buffer, buffer_size);
        if (read_len < 0) {
            ESP_LOGE(TAG, "HTTP read failed");
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        if (read_len == 0) {
            // No more data
            break;
        }

        // Write to flash
        err = esp_partition_write(partition, offset, buffer, read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += read_len;
        offset += read_len;

        // Calculate progress and speed
        auto current_time = esp_timer_get_time();
        int progress = (total_written * 100) / content_length;

        // Update progress callback periodically (every 100ms or when progress changes significantly)
        if (progress_callback && 
            (progress != last_progress || (current_time - last_progress_time) > 100000)) {

            size_t elapsed_ms = (current_time - start_time) / 1000;
            size_t speed = elapsed_ms > 0 ? (total_written * 1000) / elapsed_ms : 0;

            progress_callback(progress, speed);
            last_progress = progress;
            last_progress_time = current_time;
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (total_written != content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected %d bytes, got %d bytes", content_length, total_written);
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully: %d bytes written", total_written);

    // Verify the written data by re-initializing
    return InitializePartition();
}

bool Assets::GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    // Check if the partition is valid and checksum is valid
    if (!partition_valid_ || !checksum_valid_)
    {
        ESP_LOGE(TAG, "Assets partition is not valid or checksum failed");
        return false;
    }

    // Find the asset in the assets map
    auto it = assets_.find(name);
    if (it == assets_.end())
    {
        ESP_LOGD(TAG, "Asset %s not found", name.c_str());
        return false;
    }

    const auto &asset = it->second;

    // Bounds checking
    if (asset.offset >= partition_->size || asset.offset + asset.size > partition_->size)
    {
        ESP_LOGE(TAG, "Asset %s data is out of bounds", name.c_str());
        return false;
    }

    // Check minimum size for header
    if (asset.size < sizeof(uint32_t) * 2)
    {
        ESP_LOGE(TAG, "Asset %s is too small to contain header", name.c_str());
        return false;
    }

    // Get pointer to the asset data
    uint8_t *asset_data = reinterpret_cast<uint8_t*>(mmap_root_) + asset.offset;

    // Read the magic number and data size from the header
    uint32_t magic_number = *reinterpret_cast<uint32_t*>(asset_data);
    uint32_t data_size = *reinterpret_cast<uint32_t*>(asset_data + sizeof(uint32_t));

    // Validate magic number (assuming 0x12345678 as common magic number, adjust as needed)
    if (magic_number != 0x12345678)
    {
        ESP_LOGE(TAG, "Asset %s has invalid magic number: 0x%08lx", name.c_str(), magic_number);
        return false;
    }

    // Validate data size
    size_t header_size = sizeof(uint32_t) * 2; // magic + size
    if (data_size > asset.size - header_size)
    {
        ESP_LOGE(TAG, "Asset %s data size mismatch: declared %lu, available %lu", 
                 name.c_str(), data_size, asset.size - header_size);
        return false;
    }

    // Set output parameters
    ptr = asset_data + header_size; // Skip the header
    size = data_size;

    return true;
}

const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    // Ensure the state index is within the valid range of predefined strings
    if (state >= 0 && state < sizeof(STATE_STRINGS) / sizeof(STATE_STRINGS[0]) - 1)
    {
        return STATE_STRINGS[state];
    }
    else
    {
        return "unknown";
    }
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    // Allow self-transitions by default
    if (from == to)
        return true;

    switch (from)
    {
    case kDeviceStateUnknown:
        return to == kDeviceStateStarting;

    case kDeviceStateStarting:
        return to == kDeviceStateWifiConfiguring || to == kDeviceStateFatalError;

    case kDeviceStateWifiConfiguring:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateIdle:
        return to == kDeviceStateConnecting ||
               to == kDeviceStateListening ||
               to == kDeviceStateSpeaking ||
               to == kDeviceStateUpgrading ||
               to == kDeviceStateActivating ||
               to == kDeviceStateAudioTesting ||
               to == kDeviceStateFatalError;

    case kDeviceStateConnecting:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateListening:
        return to == kDeviceStateIdle || to == kDeviceStateSpeaking || to == kDeviceStateFatalError;

    case kDeviceStateSpeaking:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateUpgrading:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateActivating:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateAudioTesting:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateFatalError:
        // Fatal error is terminal - no outgoing transitions allowed
        return false;

    default:
        // Invalid 'from' state
        return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    DeviceState old_state = current_state_.load();

    // Validate the transition
    if (!IsValidTransition(old_state, new_state)) {
        ESP_LOGW(TAG, "Invalid state transition requested: %s -> %s",
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform atomic state update
    if (!current_state_.compare_exchange_strong(old_state, new_state)) {
        // In case another thread changed the state in the meantime
        ESP_LOGW(TAG, "State transition conflict: %s -> %s (overridden by concurrent change)",
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Successfully transitioned
    ESP_LOGI(TAG, "State transitioned: %s -> %s",
             GetStateName(old_state), GetStateName(new_state));

    // Notify all registered listeners
    NotifyStateChange(old_state, new_state);

    return true;
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    static int next_listener_id = 1;
    std::lock_guard<std::mutex> lock(mutex_);
    int listener_id = next_listener_id++;
    listeners_.emplace_back(listener_id, callback);
    return listener_id;
}

void DeviceStateMachine::RemoveStateChangeListener(int listener_id)
{
    std::lock_guard<std::mutex> lock(mutex_);
    listeners_.erase(
        std::remove_if(listeners_.begin(), listeners_.end(),
                       [listener_id](const auto& pair) { return pair.first == listener_id; }),
        listeners_.end());
}

void DeviceStateMachine::NotifyStateChange(DeviceState old_state, DeviceState new_state)
{
    // Create a copy of listeners under lock to ensure thread safety
    std::vector<std::pair<int, StateCallback>> listeners_copy;
    {
        std::lock_guard<std::mutex> lock(mutex_);
        listeners_copy = listeners_;
    }

    // Invoke all callbacks with the state change information
    for (const auto& listener : listeners_copy) {
        if (listener.second) {
            listener.second(old_state, new_state);
        }
    }
}

extern "C" void app_main(void)
{
    // Initialize NVS flash storage
    esp_err_t ret = nvs_flash_init();

    // Handle NVS corruption by erasing and reinitializing if necessary
    if (ret == ESP_ERR_NVS_NO_FREE_PAGES || ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        // Erase NVS partition and retry initialization
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK(ret);

    // Initialize the system information module
    system_info_init();

    // Create and start the main application instance
    Application* app = new Application();

    // Initialize the application
    app->init();

    // Start the application's main event loop
    // This will handle audio processing, network communication, and device state management
    app->run();

    // The application should run indefinitely in the event loop
    // If we reach here, something went wrong
    ESP_LOGE(TAG, "Application terminated unexpectedly");
}

Ota::Ota()
{
    // Initialize serial number from eFuse
    uint8_t mac[6];
    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_USER_DATA, mac, sizeof(mac) * 8);

    if (err == ESP_OK) {
        // Convert MAC bytes to hex string format
        char serial_buf[13]; // 6 bytes * 2 chars + null terminator
        snprintf(serial_buf, sizeof(serial_buf), "%02X%02X%02X%02X%02X%02X", 
                 mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
        serial_number_ = std::string(serial_buf);

        // Check if serial number is not empty (non-zero)
        if (!serial_number_.empty() && serial_number_ != "000000000000") {
            has_serial_number_ = true;
            ESP_LOGI(TAG, "Serial number initialized: %s", serial_number_.c_str());
        } else {
            has_serial_number_ = false;
            ESP_LOGW(TAG, "Empty or invalid serial number read from eFuse");
        }
    } else {
        has_serial_number_ = false;
        ESP_LOGE(TAG, "Failed to read serial number from eFuse: %s", esp_err_to_name(err));
    }
}

std::string Ota::GetCheckVersionUrl()
{
    // First try to get URL from Wi-Fi settings
    Settings wifi_settings("wifi", true);
    std::string url = wifi_settings.GetString("ota_url");

    // If URL is not set in Wi-Fi settings, use default
    if (url.empty()) {
        // Try to get from general settings
        Settings general_settings("system", true);
        url = general_settings.GetString("ota_check_url");

        // If still empty, use hardcoded default
        if (url.empty()) {
            url = "https://api.example.com/firmware/check"; // Default fallback URL
        }
    }

    ESP_LOGI(TAG, "Using OTA check version URL: %s", url.c_str());
    return url;
}

std::unique_ptr<Http> Ota::SetupHttp()
{
    auto &board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto http = network->CreateHttp(0);

    // Set common headers for OTA requests
    http->SetHeader("User-Agent", "ESP32-OTA/1.0");
    http->SetHeader("Content-Type", "application/json");

    // Set device identification headers
    http->SetHeader("X-Device-ID", board.GetMacAddress());
    http->SetHeader("X-Device-Model", CONFIG_DEVICE_MODEL);

    // Set language header
    http->SetHeader("Accept-Language", LangConfig::GetInstance().GetCurrentLanguage());

    // Set serial number header if available
    if (has_serial_number_) {
        http->SetHeader("X-Device-Serial", serial_number_);
    }

    return http;
}

esp_err_t Ota::CheckVersion()
{
    auto http = SetupHttp();
    std::string url = GetCheckVersionUrl();

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return ESP_FAIL;
    }

    if (http->GetStatusCode() != 200)
    {
        ESP_LOGE(TAG, "HTTP request failed with status code: %d", http->GetStatusCode());
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response received");
        return ESP_FAIL;
    }

    cJSON *json = cJSON_Parse(response.c_str());
    if (!json)
    {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Check for errors in response
    cJSON *error_obj = cJSON_GetObjectItem(json, "error");
    if (error_obj)
    {
        ESP_LOGE(TAG, "Server returned error: %s", error_obj->valuestring);
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    // Handle activation challenge if present
    cJSON *activation_challenge = cJSON_GetObjectItem(json, "activation_challenge");
    if (activation_challenge && cJSON_IsString(activation_challenge))
    {
        activation_challenge_ = std::string(activation_challenge->valuestring);
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Received activation challenge");
    }

    // Handle MQTT configuration if present
    cJSON *mqtt_config = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_config && cJSON_IsObject(mqtt_config))
    {
        cJSON *host = cJSON_GetObjectItem(mqtt_config, "host");
        cJSON *port = cJSON_GetObjectItem(mqtt_config, "port");
        cJSON *username = cJSON_GetObjectItem(mqtt_config, "username");
        cJSON *password = cJSON_GetObjectItem(mqtt_config, "password");

        if (host && cJSON_IsString(host))
        {
            Settings mqtt_settings("mqtt", true);
            mqtt_settings.SetString("host", host->valuestring);

            if (port && cJSON_IsNumber(port))
            {
                mqtt_settings.SetInt("port", port->valueint);
            }

            if (username && cJSON_IsString(username))
            {
                mqtt_settings.SetString("username", username->valuestring);
            }

            if (password && cJSON_IsString(password))
            {
                mqtt_settings.SetString("password", password->valuestring);
            }

            mqtt_settings.Save();
            ESP_LOGI(TAG, "MQTT configuration updated");
        }
    }

    // Check for firmware update
    cJSON *latest_version = cJSON_GetObjectItem(json, "version");
    cJSON *firmware_url = cJSON_GetObjectItem(json, "url");

    if (!latest_version || !cJSON_IsString(latest_version))
    {
        ESP_LOGE(TAG, "Invalid response: missing version information");
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    std::string current_version = esp_app_get_description()->version;
    std::string new_version = std::string(latest_version->valuestring);

    ESP_LOGI(TAG, "Current version: %s, Latest version: %s", current_version.c_str(), new_version.c_str());

    if (IsNewVersionAvailable(current_version, new_version))
    {
        if (firmware_url && cJSON_IsString(firmware_url))
        {
            firmware_url_ = std::string(firmware_url->valuestring);
            ESP_LOGI(TAG, "New firmware version available: %s", new_version.c_str());
            cJSON_Delete(json);
            return ESP_OK;
        }
        else
        {
            ESP_LOGE(TAG, "New version available but URL is missing");
            cJSON_Delete(json);
            return ESP_FAIL;
        }
    }
    else
    {
        ESP_LOGI(TAG, "Firmware is up to date");
        cJSON_Delete(json);
        return ESP_OK;
    }
}

void Ota::MarkCurrentVersionValid()
{
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    if (running_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    ESP_LOGI(TAG, "Running partition: %s at offset 0x%lx", running_partition->label, running_partition->address);

    // Skip validation for factory partition
    if (running_partition->type == ESP_PARTITION_TYPE_APP && running_partition->subtype == ESP_PARTITION_SUBTYPE_APP_FACTORY) {
        ESP_LOGI(TAG, "Running factory partition, skip validation");
        return;
    }

    // Check if the running partition is marked as pending
    esp_ota_img_states_t ota_state;
    esp_err_t err = esp_ota_get_state_partition(running_partition, &ota_state);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get partition state: %s", esp_err_to_name(err));
        return;
    }

    if (ota_state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Partition is in pending verify state, marking as valid");
        err = esp_ota_mark_app_valid_cancel_rollback();
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark app as valid: %s", esp_err_to_name(err));
        } else {
            ESP_LOGI(TAG, "Successfully marked current version as valid");
        }
    } else {
        ESP_LOGI(TAG, "Partition state is %d, no validation needed", ota_state);
    }
}

bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    if (firmware_url.empty()) {
        ESP_LOGE(TAG, "Firmware URL is empty");
        return false;
    }

    ESP_LOGI(TAG, "Starting firmware upgrade from: %s", firmware_url.c_str());

    // Find OTA app partition
    const esp_partition_t *update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             update_partition->subtype, update_partition->address);

    // Begin OTA update
    esp_ota_handle_t update_handle = 0;
    esp_err_t err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Setup HTTP connection
    auto http = SetupHttp();
    if (!http->Open("GET", firmware_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", firmware_url.c_str());
        esp_ota_end(update_handle);
        return false;
    }

    if (http->GetStatusCode() != 200) {
        ESP_LOGE(TAG, "HTTP GET failed, status code: %d", http->GetStatusCode());
        http->Close();
        esp_ota_end(update_handle);
        return false;
    }

    // Download and write firmware
    const size_t buffer_size = 4096;
    std::vector<uint8_t> buffer(buffer_size);
    size_t total_bytes_written = 0;
    size_t bytes_written_since_last_callback = 0;
    uint32_t last_callback_time = esp_log_timestamp();

    // Get content length for progress calculation
    size_t content_length = http->GetContentLength();
    bool use_progress = (content_length > 0);

    while (true) {
        ssize_t bytes_read = http->Read(buffer.data(), buffer_size);
        if (bytes_read < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            http->Close();
            esp_ota_end(update_handle);
            return false;
        }

        if (bytes_read == 0) {
            // End of stream
            break;
        }

        err = esp_ota_write(update_handle, buffer.data(), bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            http->Close();
            esp_ota_end(update_handle);
            return false;
        }

        total_bytes_written += bytes_read;
        bytes_written_since_last_callback += bytes_read;

        // Call progress callback periodically (every 100ms or every 64KB)
        uint32_t current_time = esp_log_timestamp();
        if ((current_time - last_callback_time) >= 100 || bytes_written_since_last_callback >= (64 * 1024)) {
            int progress = 0;
            if (use_progress) {
                progress = (total_bytes_written * 100) / content_length;
                if (progress > 100) progress = 100;
            }

            size_t speed = 0;
            if ((current_time - last_callback_time) > 0) {
                speed = (bytes_written_since_last_callback * 1000) / (current_time - last_callback_time);
            }

            if (callback) {
                callback(progress, speed);
            }

            bytes_written_since_last_callback = 0;
            last_callback_time = current_time;
        }
    }

    http->Close();

    ESP_LOGI(TAG, "Total bytes written: %d", total_bytes_written);

    // Finish OTA update
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Validate firmware image
    esp_app_desc_t app_desc;
    err = esp_ota_get_partition_description(update_partition, &app_desc);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get partition description: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "New firmware version: %s", app_desc.version);

    // Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully. Reboot required to apply changes.");
    return true;
}

std::vector<int> Ota::ParseVersion(const std::string &version)
{
    std::vector<int> result;
    std::stringstream ss(version);
    std::string segment;

    while (std::getline(ss, segment, '.'))
    {
        try
        {
            int num = std::stoi(segment);
            result.push_back(num);
        }
        catch (const std::exception &e)
        {
            // If conversion fails, push 0 or handle as needed
            result.push_back(0);
        }
    }

    return result;
}

bool Ota::IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    // Parse both version strings into vectors of integers
    std::vector<int> currentParts = ParseVersion(currentVersion);
    std::vector<int> newParts = ParseVersion(newVersion);

    // Compare each part from left to right
    size_t maxParts = std::max(currentParts.size(), newParts.size());

    for (size_t i = 0; i < maxParts; ++i) {
        int currentPart = (i < currentParts.size()) ? currentParts[i] : 0;
        int newPart = (i < newParts.size()) ? newParts[i] : 0;

        if (newPart > currentPart) {
            return true;  // New version is greater
        } else if (newPart < currentPart) {
            return false; // New version is smaller
        }
        // If equal, continue to next part
    }

    // All parts are equal
    return false;
}

std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        return "{}";
    }

    cJSON *root = cJSON_CreateObject();
    if (root == NULL)
    {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return "{}";
    }

    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());
    cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());

    // Generate HMAC signature
    std::string signature;
#ifdef SOC_HMAC_SUPPORTED
    if (has_activation_challenge_)
    {
        uint8_t hmac[32] = {0};
        size_t hmac_len = 0;

        // Use hardware HMAC with key 0 (should be provisioned during manufacturing)
        esp_err_t ret = esp_hmac_calculate(HMAC_KEY0, activation_challenge_.c_str(), activation_challenge_.length(), hmac);
        if (ret == ESP_OK)
        {
            // Convert binary HMAC to hex string
            std::stringstream ss;
            for (int i = 0; i < 32; i++)
            {
                ss << std::hex << std::setw(2) << std::setfill('0') << (int)hmac[i];
            }
            signature = ss.str();
            cJSON_AddStringToObject(root, "signature", signature.c_str());
        }
        else
        {
            ESP_LOGE(TAG, "Failed to calculate HMAC: %s", esp_err_to_name(ret));
        }
    }
#else
    // Software fallback - this would typically not be used in production
    // but included for completeness
    ESP_LOGW(TAG, "HMAC not supported on this chip, signature will be empty");
#endif

    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string ? json_string : "{}");

    if (json_string)
    {
        free(json_string);
    }
    cJSON_Delete(root);

    return result;
}

std::string Ota::GetActivationPayload()
{
    cJSON *root = cJSON_CreateObject();
    if (has_activation_challenge_) {
        cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());
    }

    char *json_string = cJSON_PrintUnformatted(root);
    std::string payload(json_string);
    cJSON_Delete(root);
    free(json_string);

    return payload;
}

esp_err_t Ota::Activate()
{
    if (!has_activation_challenge_)
    {
        ESP_LOGW(TAG, "No activation challenge found");
        return ESP_FAIL;
    }

    std::string url = GetCheckVersionUrl();
    if (url.back() != '/')
    {
        url += "/activate";
    }
    else
    {
        url += "activate";
    }

    auto http = SetupHttp();

    std::string data = GetActivationPayload();
    http->SetContent(std::move(data));

    if (!http->Open("POST", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code == 202)
    {
        http->Close();
        return ESP_ERR_TIMEOUT;
    }
    if (status_code != 200)
    {
        std::string response_body = http->ReadAll();
        http->Close();
        ESP_LOGE(TAG, "Failed to activate, code: %d, body: %s", status_code, response_body.c_str());
        return ESP_FAIL;
    }

    std::string response_body = http->ReadAll();
    http->Close();

    // Parse response to check for activation result
    cJSON *root = cJSON_Parse(response_body.c_str());
    if (root != NULL) {
        cJSON *result = cJSON_GetObjectItem(root, "result");
        if (result != NULL && cJSON_IsString(result)) {
            if (strcmp(result->valuestring, "success") == 0) {
                cJSON_Delete(root);
                ESP_LOGI(TAG, "Activation successful");
                return ESP_OK;
            }
        }
        cJSON_Delete(root);
    }

    ESP_LOGI(TAG, "Activation completed with response: %s", response_body.c_str());
    return ESP_OK;
}

Settings::~Settings()
{
    if (read_write_ && dirty_)
    {
        esp_err_t err = nvs_commit(nvs_handle_);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to commit NVS changes: %s", esp_err_to_name(err));
        }
    }

    if (nvs_handle_ != 0)
    {
        nvs_close(nvs_handle_);
        nvs_handle_ = 0;
    }
}

std::string Settings::GetString(const std::string &key, const std::string &default_value)
{
    if (nvs_handle_ == 0)
    {
        return default_value;
    }

    size_t required_size = 0;
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);
    if (err != ESP_OK || required_size == 0)
    {
        return default_value;
    }

    std::vector<char> buffer(required_size);
    err = nvs_get_str(nvs_handle_, key.c_str(), buffer.data(), &required_size);
    if (err != ESP_OK)
    {
        return default_value;
    }

    // Ensure no trailing null characters beyond intended string length
    std::string result(buffer.data());
    return result;
}

void Settings::SetString(const std::string &key, const std::string &value)
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_set_str(nvs_handle_, key.c_str(), value.c_str()));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

int32_t Settings::GetInt(const std::string &key, int32_t default_value)
{
    if (nvs_handle_ == 0)
    {
        return default_value;
    }

    int32_t value;
    esp_err_t err = nvs_get_i32(nvs_handle_, key.c_str(), &value);
    if (err != ESP_OK)
    {
        return default_value;
    }

    return value;
}

void Settings::SetInt(const std::string &key, int32_t value)
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_set_i32(nvs_handle_, key.c_str(), value));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

bool Settings::GetBool(const std::string &key, bool default_value)
{
    if (nvs_handle_ == 0)
    {
        return default_value;
    }

    uint8_t value = 0;
    esp_err_t err = nvs_get_u8(nvs_handle_, key.c_str(), &value);
    if (err != ESP_OK)
    {
        return default_value;
    }

    return (value != 0);
}

void Settings::SetBool(const std::string &key, bool value)
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_set_u8(nvs_handle_, key.c_str(), value ? 1 : 0));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

void Settings::EraseKey(const std::string &key)
{
    if (read_write_)
    {
        auto ret = nvs_erase_key(nvs_handle_, key.c_str());
        if (ret != ESP_ERR_NVS_NOT_FOUND)
        {
            ESP_ERROR_CHECK(ret);
        }
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

void Settings::EraseAll()
{
    if (nvs_handle_ == 0)
    {
        return;
    }

    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_erase_all(nvs_handle_));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

size_t SystemInfo::GetFlashSize()
{
    uint32_t flash_size = 0;
    esp_err_t err = esp_flash_get_size(esp_flash_default_chip, &flash_size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get flash size: %s", esp_err_to_name(err));
        return 0;
    }
    return static_cast<size_t>(flash_size);
}

std::string SystemInfo::GetMacAddress()
{
    uint8_t mac[6];
    esp_err_t err = esp_read_mac(mac, ESP_MAC_WIFI_STA);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read MAC address: %s", esp_err_to_name(err));
        return "";
    }

    char macStr[18]; // Format: XX:XX:XX:XX:XX:XX + null terminator
    snprintf(macStr, sizeof(macStr), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    return std::string(macStr);
}

std::string SystemInfo::GetUserAgent()
{
    auto desc = esp_app_get_description();
    if (desc == nullptr) {
        ESP_LOGE(TAG, "Failed to get application description");
        return "";
    }

    std::string board_name = CONFIG_IDF_TARGET;
    std::string version = desc->version;

    return board_name + "/" + version;
}

esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    TaskStatus_t *pxTaskStatusArray_initial;
    TaskStatus_t *pxTaskStatusArray_final;
    volatile UBaseType_t uxArraySize_initial, uxArraySize_final;
    uint32_t ulTotalRunTime_initial, ulTotalRunTime_final;
    uint32_t ulRunTimeDifference;
    uint32_t ulTotalRunTimeDifference;
    float fUsagePercent;

    // Take initial snapshot
    uxArraySize_initial = uxTaskGetNumberOfTasks();
    pxTaskStatusArray_initial = (TaskStatus_t*)malloc(uxArraySize_initial * sizeof(TaskStatus_t));
    if (pxTaskStatusArray_initial == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for initial task status array");
        return ESP_ERR_NO_MEM;
    }

    uxArraySize_initial = uxTaskGetSystemState(pxTaskStatusArray_initial, uxArraySize_initial, &ulTotalRunTime_initial);
    if (uxArraySize_initial == 0) {
        ESP_LOGE(TAG, "Failed to get initial task state");
        free(pxTaskStatusArray_initial);
        return ESP_FAIL;
    }

    // Wait for specified time
    vTaskDelay(xTicksToWait);

    // Take final snapshot
    uxArraySize_final = uxTaskGetNumberOfTasks();
    pxTaskStatusArray_final = (TaskStatus_t*)malloc(uxArraySize_final * sizeof(TaskStatus_t));
    if (pxTaskStatusArray_final == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for final task status array");
        free(pxTaskStatusArray_initial);
        return ESP_ERR_NO_MEM;
    }

    uxArraySize_final = uxTaskGetSystemState(pxTaskStatusArray_final, uxArraySize_final, &ulTotalRunTime_final);
    if (uxArraySize_final == 0) {
        ESP_LOGE(TAG, "Failed to get final task state");
        free(pxTaskStatusArray_initial);
        free(pxTaskStatusArray_final);
        return ESP_FAIL;
    }

    // Calculate total run time difference
    ulTotalRunTimeDifference = ulTotalRunTime_final - ulTotalRunTime_initial;

    if (ulTotalRunTimeDifference == 0) {
        ESP_LOGW(TAG, "No run time difference detected");
        free(pxTaskStatusArray_initial);
        free(pxTaskStatusArray_final);
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Task CPU Usage over %lu ticks:", xTicksToWait);

    // Compare tasks and calculate usage
    for (UBaseType_t x = 0; x < uxArraySize_initial; x++) {
        bool task_found = false;
        for (UBaseType_t y = 0; y < uxArraySize_final; y++) {
            if (pxTaskStatusArray_initial[x].xHandle == pxTaskStatusArray_final[y].xHandle) {
                task_found = true;
                ulRunTimeDifference = pxTaskStatusArray_final[y].ulRunTimeCounter - pxTaskStatusArray_initial[x].ulRunTimeCounter;
                fUsagePercent = (float)(ulRunTimeDifference * 100.0) / (float)ulTotalRunTimeDifference;

                ESP_LOGI(TAG, "Task: %-16s CPU: %6.2f%% State: %d",
                         pxTaskStatusArray_initial[x].pcTaskName,
                         fUsagePercent,
                         pxTaskStatusArray_initial[x].eCurrentState);
                break;
            }
        }
        if (!task_found) {
            ESP_LOGI(TAG, "Task: %-16s was deleted during measurement",
                     pxTaskStatusArray_initial[x].pcTaskName);
        }
    }

    // Check for newly created tasks
    for (UBaseType_t y = 0; y < uxArraySize_final; y++) {
        bool task_found = false;
        for (UBaseType_t x = 0; x < uxArraySize_initial; x++) {
            if (pxTaskStatusArray_initial[x].xHandle == pxTaskStatusArray_final[y].xHandle) {
                task_found = true;
                break;
            }
        }
        if (!task_found) {
            ESP_LOGI(TAG, "Task: %-16s was created during measurement",
                     pxTaskStatusArray_final[y].pcTaskName);
        }
    }

    free(pxTaskStatusArray_initial);
    free(pxTaskStatusArray_final);

    return ESP_OK;
}

void SystemInfo::PrintTaskList()
{
    // Allocate a buffer to hold the task list string
    // Each task entry takes roughly 40 chars; adjust size accordingly
    const size_t buf_size = 1024;
    char* task_list_buffer = (char*)calloc(buf_size, sizeof(char));

    if (task_list_buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task list");
        return;
    }

    // Populate the buffer with task list from FreeRTOS
    vTaskList(task_list_buffer);

    // Print header
    ESP_LOGI(TAG, "\nTask List:\nName\t\tState\tPrio\tStackMin\tNum");

    // Split the buffer by newlines and print each line
    char* line = strtok(task_list_buffer, "\n");
    while (line != NULL) {
        ESP_LOGI(TAG, "%s", line);
        line = strtok(NULL, "\n");
    }

    free(task_list_buffer);
}

void SystemInfo::PrintHeapStats()
{
    size_t free_heap = heap_caps_get_free_size(MALLOC_CAP_INTERNAL);
    size_t min_free_heap = heap_caps_get_minimum_free_size(MALLOC_CAP_INTERNAL);

    ESP_LOGI(TAG, "Current free internal heap: %d bytes", free_heap);
    ESP_LOGI(TAG, "Minimum free internal heap: %d bytes", min_free_heap);
}

bool AudioCodec::InputData(std::vector<int16_t> &data)
{
    if (!input_enabled_ || rx_handle_ == nullptr)
    {
        return false;
    }

    size_t bytes_read = 0;
    esp_err_t ret = i2s_channel_read(rx_handle_, data.data(), data.size() * sizeof(int16_t), &bytes_read, portMAX_DELAY);

    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to read audio data: %s", esp_err_to_name(ret));
        return false;
    }

    // Convert bytes to sample count
    size_t samples_read = bytes_read / sizeof(int16_t);

    // Resize vector to actual samples read
    if (samples_read != data.size())
    {
        data.resize(samples_read);
    }

    // Apply input gain if necessary
    if (input_gain_ != 1.0f)
    {
        for (auto& sample : data)
        {
            int32_t amplified = static_cast<int32_t>(sample) * input_gain_;
            // Clamp to int16_t range
            if (amplified > INT16_MAX)
                amplified = INT16_MAX;
            else if (amplified < INT16_MIN)
                amplified = INT16_MIN;
            sample = static_cast<int16_t>(amplified);
        }
    }

    return samples_read > 0;
}

void AudioCodec::Start()
{
    // Load saved settings or apply defaults
    Settings settings("audio", true);
    output_volume_ = settings.GetInt("output_volume", 50); // Default to 50 if not found
    ESP_LOGI(TAG, "Loaded output volume: %d", output_volume_);

    // Initialize I2S for both input and output
    i2s_chan_config_t chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_AUTO, I2S_ROLE_MASTER);
    i2s_new_channel(&chan_cfg, &tx_handle_, &rx_handle_);

    // Configure I2S transmit channel
    if (tx_handle_ != nullptr) {
        i2s_std_config_t std_cfg = {
            .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(48000), // Assuming 48kHz sample rate
            .slot_cfg = I2S_STD_MSB_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
            .gpio_cfg = {
                .mclk = I2S_GPIO_UNUSED,
                .bclk = GPIO_NUM_1,
                .ws = GPIO_NUM_2,
                .dout = GPIO_NUM_3,
                .din = GPIO_NUM_4,
                .invert_flags = {
                    .mclk_inv = false,
                    .bclk_inv = false,
                    .ws_inv = false,
                },
            },
        };
        i2s_channel_init_std_mode(tx_handle_, &std_cfg);
        i2s_channel_enable(tx_handle_);
    }

    // Configure I2S receive channel
    if (rx_handle_ != nullptr) {
        i2s_std_config_t std_cfg = {
            .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(48000), // Assuming 48kHz sample rate
            .slot_cfg = I2S_STD_MSB_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
            .gpio_cfg = {
                .mclk = I2S_GPIO_UNUSED,
                .bclk = GPIO_NUM_1,
                .ws = GPIO_NUM_2,
                .dout = GPIO_NUM_3,
                .din = GPIO_NUM_4,
                .invert_flags = {
                    .mclk_inv = false,
                    .bclk_inv = false,
                    .ws_inv = false,
                },
            },
        };
        i2s_channel_init_std_mode(rx_handle_, &std_cfg);
        i2s_channel_enable(rx_handle_);
    }

    // Enable input and output paths based on saved state or defaults
    EnableInput(input_enabled_);
    EnableOutput(output_enabled_);

    ESP_LOGI(TAG, "Audio codec started successfully");
}

void AudioCodec::SetOutputVolume(int volume)
{
    output_volume_ = volume;
    Settings settings("audio", true);
    settings.SetInt("output_volume", output_volume_);
    ESP_LOGI(TAG, "Set output volume to %d", output_volume_);
}

void AudioCodec::SetInputGain(float gain)
{
    input_gain_ = gain;
    ESP_LOGI(TAG, "Set input gain to %.2f", input_gain_);
}

void AudioCodec::EnableInput(bool enable)
{
    if (enable == input_enabled_)
    {
        return;
    }
    input_enabled_ = enable;
    ESP_LOGI(TAG, "Set input enable to %s", enable ? "true" : "false");
}

void AudioCodec::EnableOutput(bool enable)
{
    if (enable == output_enabled_)
    {
        return;
    }
    output_enabled_ = enable;
    ESP_LOGI(TAG, "Set output enable to %s", enable ? "true" : "false");

    if (tx_handle_ != nullptr)
    {
        if (enable)
        {
            ESP_ERROR_CHECK(i2s_channel_enable(tx_handle_));
        }
        else
        {
            ESP_ERROR_CHECK(i2s_channel_disable(tx_handle_));
        }
    }
}

Es8388AudioCodec::Es8388AudioCodec(void* i2c_master_handle, i2c_port_t i2c_port, int input_sample_rate, int output_sample_rate,
                                   gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din, gpio_num_t pa_pin,
                                   uint8_t address, bool input_reference)
    : input_sample_rate_(input_sample_rate)
    , output_sample_rate_(output_sample_rate)
    , input_channels_(input_reference ? 2 : 1)
    , output_channels_(1)
    , pa_pin_(pa_pin)
    , input_reference_(input_reference)
    , input_gain_(0)
    , output_volume_(50)
    , input_enabled_(false)
    , output_enabled_(false)
    , tx_handle_(nullptr)
    , rx_handle_(nullptr)
    , ctrl_if_(nullptr)
    , codec_if_(nullptr)
    , gpio_if_(nullptr)
    , data_if_(nullptr)
    , input_dev_(nullptr)
    , output_dev_(nullptr)
{
    // Create I2C control interface
    audio_codec_i2c_cfg_t i2c_cfg = {
        .port = i2c_port,
        .addr = address,
        .bus_handle = (i2c_master_bus_handle_t)i2c_master_handle,
    };
    ctrl_if_ = audio_codec_new_i2c_ctrl(&i2c_cfg);

    // Create ES8388 codec interface
    codec_if_ = es8388_codec_new(ctrl_if_);

    // Create GPIO interface for power amplifier control
    if (pa_pin_ != GPIO_NUM_NC) {
        audio_codec_gpio_cfg_t gpio_cfg = {
            .gpio_intr_type = GPIO_INTR_DISABLE,
            .gpio_pull_down = false,
            .gpio_pull_up = false,
            .gpio_mode = GPIO_MODE_OUTPUT,
        };
        gpio_if_ = audio_codec_new_gpio();
        gpio_if_->setup(gpio_if_, (int)pa_pin_, &gpio_cfg);
        gpio_set_level(pa_pin_, 0);
    }

    // Create data interface
    data_if_ = audio_codec_new_i2s_data(I2S_NUM_0);

    // Create input device
    input_dev_ = esp_codec_dev_new(codec_if_, ctrl_if_, data_if_, gpio_if_);
    if (input_dev_) {
        esp_codec_dev_set_role(input_dev_, ESP_CODEC_DEV_TYPE_IN);
    }

    // Create output device
    output_dev_ = esp_codec_dev_new(codec_if_, ctrl_if_, data_if_, gpio_if_);
    if (output_dev_) {
        esp_codec_dev_set_role(output_dev_, ESP_CODEC_DEV_TYPE_OUT);
    }

    // Create duplex channels
    CreateDuplexChannels(mclk, bclk, ws, dout, din);
}

Es8388AudioCodec::~Es8388AudioCodec()
{
    // Close devices first if they are open
    if (input_dev_) {
        esp_codec_dev_close(input_dev_);
    }
    if (output_dev_) {
        esp_codec_dev_close(output_dev_);
    }

    // Delete devices
    if (input_dev_) {
        esp_codec_dev_delete(input_dev_);
        input_dev_ = nullptr;
    }
    if (output_dev_) {
        esp_codec_dev_delete(output_dev_);
        output_dev_ = nullptr;
    }

    // Delete codec interface
    if (codec_if_) {
        es8388_codec_delete(codec_if_);
        codec_if_ = nullptr;
    }

    // Delete interfaces
    if (ctrl_if_) {
        audio_codec_delete_i2c_ctrl(ctrl_if_);
        ctrl_if_ = nullptr;
    }
    if (gpio_if_) {
        audio_codec_delete_gpio(gpio_if_);
        gpio_if_ = nullptr;
    }
    if (data_if_) {
        audio_codec_delete_i2s_data(data_if_);
        data_if_ = nullptr;
    }

    // Delete I2S channels
    if (rx_handle_) {
        i2s_del_channel(rx_handle_);
        rx_handle_ = nullptr;
    }
    if (tx_handle_) {
        i2s_del_channel(tx_handle_);
        tx_handle_ = nullptr;
    }

    ESP_LOGI(TAG, "Es8388AudioCodec destroyed");
}

void Es8388AudioCodec::CreateDuplexChannels(gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din)
{
    // Configure I2S TX channel (output)
    i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    tx_chan_cfg.auto_clear = true;
    ESP_ERROR_CHECK(i2s_new_channel(&tx_chan_cfg, &tx_handle_, NULL));

    // Configure I2S RX channel (input)
    i2s_chan_config_t rx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    ESP_ERROR_CHECK(i2s_new_channel(&rx_chan_cfg, NULL, &rx_handle_));

    // Configure I2S common settings
    i2s_std_config_t std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(input_sample_rate_),
        .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = mclk,
            .bclk = bclk,
            .ws = ws,
            .dout = dout,
            .din = din,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false,
            },
        },
    };

    // Apply configuration to both channels
    ESP_ERROR_CHECK(i2s_channel_init_std_mode(tx_handle_, &std_cfg));
    ESP_ERROR_CHECK(i2s_channel_init_std_mode(rx_handle_, &std_cfg));
}

void Es8388AudioCodec::SetOutputVolume(int volume)
{
    // Clamp volume to valid range (typically 0-100)
    if (volume < 0) volume = 0;
    if (volume > 100) volume = 100;

    // Update internal volume state
    output_volume_ = volume;

    // Set the actual hardware volume if device is available
    if (output_dev_) {
        ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, volume));
    }

    // If there's a parent class method, call it
    // AudioCodec::SetOutputVolume(volume);
}

void Es8388AudioCodec::EnableInput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == input_enabled_)
    {
        return;
    }
    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = (uint32_t)input_channels_,
            .channel_mask = 0,
            .sample_rate = (uint32_t)input_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(input_dev_, &fs));

        // Set input gain
        ESP_ERROR_CHECK(esp_codec_dev_set_in_gain(input_dev_, input_gain_));

        // Additional ES8388 specific register configuration for input
        if (input_reference_)
        {
            // Configure for reference input (stereo mode for echo cancellation)
            uint8_t reg_val = 0x00; // Example value, actual depends on ES8388 datasheet
            ctrl_if_->write_reg(ctrl_if_, 0x08, 1, &reg_val, 1); // ADC Control Reg 1
            ctrl_if_->write_reg(ctrl_if_, 0x09, 1, &reg_val, 1); // ADC Control Reg 2
        }
        else
        {
            // Configure for single microphone input
            uint8_t reg_val = 0x00; // Example value
            ctrl_if_->write_reg(ctrl_if_, 0x08, 1, &reg_val, 1);
        }
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(input_dev_));
    }
    AudioCodec::EnableInput(enable);
}

void Es8388AudioCodec::EnableOutput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == output_enabled_)
    {
        return;
    }
    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = 2,  // Stereo output
            .channel_mask = ESP_CODEC_DEV_MAKE_CHANNEL_MASK(0) | ESP_CODEC_DEV_MAKE_CHANNEL_MASK(1),
            .sample_rate = (uint32_t)output_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(output_dev_, &fs));
        ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, output_volume_));

        // Enable power amplifier pin if configured
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_if_->setup(pa_pin_, GPIO_MODE_OUTPUT);
            gpio_if_->set(pa_pin_, 1);  // Active high for most amplifiers
        }
    }
    else
    {
        // Disable power amplifier pin if configured
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_if_->set(pa_pin_, 0);
        }
        ESP_ERROR_CHECK(esp_codec_dev_close(output_dev_));
    }
    AudioCodec::EnableOutput(enable);
}

int Es8388AudioCodec::Read(int16_t *dest, int samples)
{
    if (input_enabled_ && input_dev_ && dest != nullptr)
    {
        ESP_ERROR_CHECK_WITHOUT_ABORT(esp_codec_dev_read(input_dev_, (void *)dest, samples * sizeof(int16_t)));
    }
    return samples;
}

int Es8388AudioCodec::Write(const int16_t *data, int samples)
{
    if (!output_enabled_ || !output_dev_ || !data) {
        return 0;
    }

    size_t bytes_to_write = samples * sizeof(int16_t);
    esp_err_t result = esp_codec_dev_write(output_dev_, (void *)data, bytes_to_write);

    if (result != ESP_OK) {
        ESP_LOGW(TAG, "Failed to write audio data: %s", esp_err_to_name(result));
        return 0;
    }

    return samples;
}

AudioDebugger::AudioDebugger()
    : udp_sockfd_(-1)
{
#if CONFIG_USE_AUDIO_DEBUGGER
    // Create UDP socket
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0)
    {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    // Zero out server address structure
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));

    // Setup server address
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(CONFIG_AUDIO_DEBUG_UDP_PORT);

    // Convert IP address string to binary form
    if (inet_aton(CONFIG_AUDIO_DEBUG_UDP_SERVER, &udp_server_addr_.sin_addr) == 0)
    {
        ESP_LOGE(TAG, "Invalid server IP address: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "Initialized UDP socket to %s:%d", CONFIG_AUDIO_DEBUG_UDP_SERVER, CONFIG_AUDIO_DEBUG_UDP_PORT);
#endif
}

AudioDebugger::~AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ >= 0)
    {
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        ESP_LOGD(TAG, "UDP socket closed");
    }
#endif
}

void AudioDebugger::Feed(const std::vector<int16_t> &data)
{
#if CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ < 0 || data.empty()) {
        return;
    }

    const void* buffer = data.data();
    size_t length = data.size() * sizeof(int16_t);

    ssize_t sent_bytes = sendto(
        udp_sockfd_,
        buffer,
        length,
        0,
        reinterpret_cast<const struct sockaddr*>(&udp_server_addr_),
        sizeof(udp_server_addr_)
    );

    if (sent_bytes < 0) {
        ESP_LOGE(TAG, "Failed to send audio data: errno %d", errno);
    } else if (static_cast<size_t>(sent_bytes) != length) {
        ESP_LOGW(TAG, "Incomplete UDP send: sent %d of %zu bytes", sent_bytes, length);
    } else {
        ESP_LOGD(TAG, "Sent %zu bytes of audio data", length);
    }
#endif // CONFIG_USE_AUDIO_DEBUGGER
}

AfeWakeWord::AfeWakeWord()
{
    event_group_ = xEventGroupCreate();
    afe_data_ = nullptr;
    afe_iface_ = nullptr;
    models_ = nullptr;
    wake_word_encode_task_stack_ = nullptr;
    wake_word_encode_task_buffer_ = nullptr;
    wake_word_encode_task_ = nullptr;
}

AfeWakeWord::~AfeWakeWord()
{
    // Clean up AFE instance
    if (afe_data_ != nullptr && afe_iface_ != nullptr) {
        afe_iface_->destroy(afe_data_);
        afe_data_ = nullptr;
    }

    // Clean up event group
    if (event_group_ != nullptr) {
        vEventGroupDelete(event_group_);
        event_group_ = nullptr;
    }

    // Clean up wake word encoding task stack
    if (wake_word_encode_task_stack_ != nullptr) {
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    // Clean up wake word encoding task buffer
    if (wake_word_encode_task_buffer_ != nullptr) {
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }

    // Clear wake word data containers
    wake_word_pcm_.clear();
    wake_word_opus_.clear();

    // Note: models_ cleanup depends on ownership semantics
    // If models_ was created with esp_srmodel_init and we own it, we should clean it up
    // However, if it was passed in from outside, we shouldn't free it
    // Based on the Initialize method, we only call esp_srmodel_init when models_list is nullptr
    // So we might need to track ownership or follow the library's cleanup protocol

    // Clear callbacks
    wake_word_detected_callback_ = nullptr;
}

bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    audio_codec_ = codec;
    models_ = models_list;

    // Load wake word models
    auto models = esp_srmodel_init(models_);
    if (models == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize speech recognition models");
        return false;
    }

    // Get wake word model names
    int wake_word_num = esp_srmodel_get_wakenet_model_num(models);
    wake_words_.resize(wake_word_num);
    for (int i = 0; i < wake_word_num; i++) {
        wake_words_[i] = esp_srmodel_get_wakenet_model_name(models, i + 1);
        ESP_LOGI(TAG, "Loaded wake word model: %s", wake_words_[i].c_str());
    }

    // Initialize AFE interface
    afe_config_t afe_config = {
        .aec_en = false,
        .se_en = false,
        .vad_en = true,
        .wakenet_en = true,
        .voice_communication_agc_en = false,
        .voice_communication_agc_gain = 0,
        .voice_detection_agc_en = true,
        .voice_detection_agc_gain = 15,
        .vad_mode = VAD_MODE_3,
        .wakenet_model_name = wake_words_[0].c_str(),
        .wakenet_mode = DET_MODE_3,
        .afe_linear_gain = 1.0,
        .afe_mode = SRMODE_LOW_COST,
        .afe_perferred_core = 0,
        .afe_perferred_priority = 5,
        .malloc_place = AFE_Malloc_Spiram,
        .agc_mode = AFE_MN_PEAK_AGC_MODE_3,
        .pcm_config = {
            .total_ch_num = 1,
            .mic_num = 1,
            .ref_num = 0,
            .sample_rate = 16000,
        }
    };

    afe_data_ = afe_init(&afe_config);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize AFE");
        return false;
    }

    afe_iface_ = afe_get_interface();
    if (afe_iface_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get AFE interface");
        return false;
    }

    // Create audio detection task
    const size_t stack_size = 4096 * 2;
    audio_detection_task_stack_ = (StackType_t *)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
    if (audio_detection_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate audio detection task stack");
        return false;
    }

    audio_detection_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
    if (audio_detection_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate audio detection task buffer");
        return false;
    }

    audio_detection_task_ = xTaskCreateStatic([](void *arg) {
        auto this_ = (AfeWakeWord*)arg;
        this_->AudioDetectionTask();
        vTaskDelete(NULL);
    }, "afe_detect", stack_size, this, 5, audio_detection_task_stack_, audio_detection_task_buffer_);

    if (audio_detection_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        return false;
    }

    ESP_LOGI(TAG, "AFE wake word detection initialized successfully");
    return true;
}

void AfeWakeWord::Stop()
{
    // Clear the event flag to halt the detection loop
    xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);

    // Reset the AFE buffer if it's initialized
    if (afe_data_ != nullptr && afe_iface_ != nullptr) {
        afe_iface_->reset(afe_data_);
    }
}

void AfeWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (afe_data_ == nullptr) {
        return;
    }

    afe_iface_->feed(afe_data_, data.data());
}

size_t AfeWakeWord::GetFeedSize()
{
    if (afe_data_ == nullptr) {
        return 0;
    }
    return afe_iface_->get_feed_chunksize(afe_data_);
}

void AfeWakeWord::AudioDetectionTask()
{
    while (true) {
        // Wait for detection to be started
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                              DETECTION_RUNNING_EVENT,
                                              pdFALSE, 
                                              pdFALSE, 
                                              portMAX_DELAY);

        if (!(bits & DETECTION_RUNNING_EVENT)) {
            continue;
        }

        // Fetch audio data from AFE
        int fetch_result = afe_iface_->fetch(afe_data_);

        if (fetch_result == 0) {
            // No data available, yield to other tasks
            vTaskDelay(1);
            continue;
        }

        // Check if wake word was detected
        if (fetch_result > 0) {
            // Wake word detected
            int wake_word_id = fetch_result;

            // Stop detection temporarily
            xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);

            // Get the wake word string
            std::string detected_word;
            if (wake_word_id > 0 && wake_word_id <= static_cast<int>(wake_words_.size())) {
                detected_word = wake_words_[wake_word_id - 1];
            } else {
                detected_word = "unknown";
            }

            ESP_LOGI(TAG, "Wake word detected: %s (ID: %d)", detected_word.c_str(), wake_word_id);

            // Store wake word audio data
            // Assuming we want to store data from the AFE buffer
            size_t chunk_size = afe_iface_->get_fetch_chunksize(afe_data_);
            const int16_t* audio_data = afe_iface_->get_fetch_buffer(afe_data_);
            StoreWakeWordData(audio_data, chunk_size);

            // Encode the stored wake word data
            EncodeWakeWordData();

            // Trigger callback if set
            if (wake_word_detected_callback_) {
                wake_word_detected_callback_(detected_word);
            }

            // Small delay before re-enabling detection to avoid multiple triggers
            vTaskDelay(pdMS_TO_TICKS(500));

            // Re-enable detection
            xEventGroupSetBits(event_group_, DETECTION_RUNNING_EVENT);
        }
    }
}

void AfeWakeWord::StoreWakeWordData(const int16_t *data, size_t samples)
{
    if (samples == 0) {
        return;
    }

    // Create a copy of the incoming data
    std::vector<int16_t> chunk(data, data + samples);

    // Add the new chunk to the end of our buffer
    wake_word_pcm_.emplace_back(std::move(chunk));

    // Calculate total samples in buffer
    size_t total_samples = 0;
    for (const auto& pcm_chunk : wake_word_pcm_) {
        total_samples += pcm_chunk.size();
    }

    // Maintain approximately 2 seconds of audio (16kHz * 2 = 32,000 samples)
    const size_t MAX_SAMPLES = 32000;

    // Remove old chunks from the front if we exceed the limit
    while (!wake_word_pcm_.empty() && total_samples > MAX_SAMPLES) {
        size_t front_chunk_size = wake_word_pcm_.front().size();
        if (total_samples - front_chunk_size >= MAX_SAMPLES) {
            // We can safely remove the entire front chunk
            total_samples -= front_chunk_size;
            wake_word_pcm_.pop_front();
        } else {
            // We need to partially trim the front chunk or stop removing
            break;
        }
    }
}

void AfeWakeWord::EncodeWakeWordData()
{
    // Allocate stack for the encoding task (use SPIRAM if available)
    wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(4096 * sizeof(StackType_t), MALLOC_CAP_SPIRAM);
    if (wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate stack for wake word encode task");
        return;
    }

    // Allocate task buffer (use internal memory for better performance)
    wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    if (wake_word_encode_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return;
    }

    // Create the encoding task
    encode_task_handle_ = xTaskCreateStatic(
        [](void *arg) {
            auto this_ = (AfeWakeWord *)arg;
            this_->EncodeTask();
            vTaskDelete(NULL);
        },
        "wake_word_encode",
        4096,
        this,
        5, // Higher priority for real-time encoding
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (encode_task_handle_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
    }
}

void AfeWakeWord::EncodeTask()
{
    // Initialize Opus encoder with low complexity settings
    OpusEncoder *encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
    if (encoder == nullptr) {
        ESP_LOGE(TAG, "Failed to create Opus encoder");
        return;
    }

    // Configure encoder for low complexity and real-time performance
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));          // Lowest complexity
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(16000));         // 16 kbps
    opus_encoder_ctl(encoder, OPUS_SET_VBR(0));                 // CBR for predictable performance
    opus_encoder_ctl(encoder, OPUS_SET_DTX(0));                 // Disable DTX for consistent processing
    opus_encoder_ctl(encoder, OPUS_SET_INBAND_FEC(0));          // Disable FEC to reduce overhead

    const size_t frame_size = 512;  // 32ms at 16kHz (matches typical chunk size)
    const size_t max_packet_size = 1276; // Maximum Opus packet size

    std::vector<uint8_t> encoded_packet(max_packet_size);

    ESP_LOGI(TAG, "Wake word encode task started");

    while (true) {
        std::vector<int16_t> pcm_frame;
        {
            std::unique_lock<std::mutex> lock(wake_word_mutex_);

            // Wait for PCM data to be available
            wake_word_cv_.wait(lock, [this]() {
                return !wake_word_pcm_.empty() || !running_;
            });

            if (!running_ && wake_word_pcm_.empty()) {
                break;
            }

            if (!wake_word_pcm_.empty()) {
                pcm_frame = std::move(wake_word_pcm_.front());
                wake_word_pcm_.pop_front();
            }
        }

        if (!pcm_frame.empty()) {
            // Ensure we have the correct frame size
            if (pcm_frame.size() != frame_size) {
                pcm_frame.resize(frame_size, 0); // Pad with zeros if needed
            }

            // Encode the PCM frame to Opus
            int encoded_bytes = opus_encode(encoder, pcm_frame.data(), frame_size, 
                                          encoded_packet.data(), max_packet_size);

            if (encoded_bytes > 0) {
                // Store the encoded Opus packet
                std::unique_lock<std::mutex> lock(wake_word_mutex_);
                wake_word_opus_.emplace_back(std::vector<uint8_t>(encoded_packet.begin(), 
                                                                encoded_packet.begin() + encoded_bytes));

                // Notify waiting consumers
                wake_word_cv_.notify_one();

                // Limit buffer size to prevent memory issues
                if (wake_word_opus_.size() > 100) { // Keep ~3 seconds of encoded data
                    wake_word_opus_.pop_front();
                }
            } else {
                ESP_LOGW(TAG, "Opus encoding failed with error: %d", encoded_bytes);
            }
        }

        // Small delay to prevent starving other tasks
        vTaskDelay(1);
    }

    // Cleanup
    opus_encoder_destroy(encoder);
    ESP_LOGI(TAG, "Wake word encode task stopped");
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until we have data available
    wake_word_cv_.wait(lock, [this] { 
        return !wake_word_opus_.empty(); 
    });

    // Get the first available opus packet
    opus = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // Return true if this is valid data (not the sentinel empty packet)
    // The sentinel empty packet is used to signal encoding completion
    return !opus.empty();
}

CustomWakeWord::~CustomWakeWord()
{
    // Clean up multinet model data if it was created
    if (multinet_ && multinet_model_data_) {
        multinet_->destroy(multinet_model_data_);
        multinet_model_data_ = nullptr;
    }

    // Free task stack memory if allocated
    if (wake_word_encode_task_stack_) {
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    // Free task buffer memory if allocated
    if (wake_word_encode_task_buffer_) {
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }

    // Clear any remaining PCM data
    wake_word_pcm_.clear();

    // Clear any remaining Opus data
    wake_word_opus_.clear();
}

bool CustomWakeWord::ParseWakenetModelConfig()
{
    // Read index.json
    auto &assets = Assets::GetInstance();
    void *ptr = nullptr;
    size_t size = 0;
    if (!assets.GetAssetData("index.json", ptr, size))
    {
        ESP_LOGE(TAG, "Failed to read index.json");

#ifdef CONFIG_CUSTOM_WAKE_WORD
        // Fallback to default configuration
        language_ = "cn";
        duration_ = 3000; // Default 3 seconds
        threshold_ = CONFIG_CUSTOM_WAKE_WORD_THRESHOLD / 100.0f;
        commands_.clear();
        commands_.push_back({CONFIG_CUSTOM_WAKE_WORD, CONFIG_CUSTOM_WAKE_WORD_DISPLAY, "wake"});

        models_ = esp_srmodel_init("model");
        if (models_ == nullptr || models_->num == -1)
        {
            ESP_LOGE(TAG, "Failed to initialize wakenet model");
            return false;
        }

        // Initialize multinet (command word recognition)
        mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, language_.c_str());
        if (mn_name_ == nullptr)
        {
            ESP_LOGW(TAG, "Language '%s' multinet not found, falling back to any multinet model", language_.c_str());
            mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, NULL);
        }
        if (mn_name_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to initialize multinet, mn_name is nullptr");
            ESP_LOGI(TAG, "Please refer to https://pcn7cs20v8cr.feishu.cn/wiki/CpQjwQsCJiQSWSkYEvrcxcbVnwh to add custom wake word");
            return false;
        }

        multinet_ = esp_mn_handle_from_name(mn_name_);
        multinet_model_data_ = multinet_->create(mn_name_, duration_);
        multinet_->set_det_threshold(multinet_model_data_, threshold_);
        esp_mn_commands_clear();
        for (int i = 0; i < commands_.size(); i++)
        {
            esp_mn_commands_add(i + 1, commands_[i].command.c_str());
        }
        esp_mn_commands_update();

        multinet_->print_active_speech_commands(multinet_model_data_);
        return true;
#else
        return false;
#endif
    }

    cJSON *root = cJSON_ParseWithLength(static_cast<char *>(ptr), size);
    if (root == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    // Clear existing commands
    commands_.clear();

    // Parse language
    cJSON *language_item = cJSON_GetObjectItem(root, "language");
    if (language_item && cJSON_IsString(language_item))
    {
        language_ = language_item->valuestring;
    }
    else
    {
        language_ = "cn"; // Default to Chinese
    }

    // Parse duration
    cJSON *duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item && cJSON_IsNumber(duration_item))
    {
        duration_ = duration_item->valueint;
    }
    else
    {
        duration_ = 3000; // Default 3 seconds
    }

    // Parse threshold
    cJSON *threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item))
    {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
    }
    else
    {
#ifdef CONFIG_CUSTOM_WAKE_WORD_THRESHOLD
        threshold_ = CONFIG_CUSTOM_WAKE_WORD_THRESHOLD / 100.0f;
#else
        threshold_ = 0.6f; // Default threshold
#endif
    }

    // Parse commands
    cJSON *commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array && cJSON_IsArray(commands_array))
    {
        int commands_count = cJSON_GetArraySize(commands_array);
        for (int i = 0; i < commands_count; i++)
        {
            cJSON *command_item = cJSON_GetArrayItem(commands_array, i);
            if (command_item)
            {
                cJSON *command_str = cJSON_GetObjectItem(command_item, "command");
                cJSON *text_str = cJSON_GetObjectItem(command_item, "text");
                cJSON *action_str = cJSON_GetObjectItem(command_item, "action");

                if (command_str && text_str && action_str &&
                    cJSON_IsString(command_str) && cJSON_IsString(text_str) && cJSON_IsString(action_str))
                {
                    commands_.push_back({
                        command_str->valuestring,
                        text_str->valuestring,
                        action_str->valuestring
                    });

                    ESP_LOGD(TAG, "Parsed command: %s -> %s (%s)", 
                             command_str->valuestring, 
                             text_str->valuestring, 
                             action_str->valuestring);
                }
            }
        }
    }
#ifdef CONFIG_CUSTOM_WAKE_WORD
    else
    {
        // Add default wake word if no commands found in JSON and config is enabled
        commands_.push_back({CONFIG_CUSTOM_WAKE_WORD, CONFIG_CUSTOM_WAKE_WORD_DISPLAY, "wake"});
    }
#endif

    cJSON_Delete(root);

    // Initialize models
    models_ = esp_srmodel_init("model");
    if (models_ == nullptr || models_->num == -1)
    {
        ESP_LOGE(TAG, "Failed to initialize wakenet model");
        return false;
    }

    // Initialize multinet (command word recognition)
    mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, language_.c_str());
    if (mn_name_ == nullptr)
    {
        ESP_LOGW(TAG, "Language '%s' multinet not found, falling back to any multinet model", language_.c_str());
        mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, NULL);
    }
    if (mn_name_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to initialize multinet, mn_name is nullptr");
        ESP_LOGI(TAG, "Please refer to https://pcn7cs20v8cr.feishu.cn/wiki/CpQjwQsCJiQSWSkYEvrcxcbVnwh to add custom wake word");
        return false;
    }

    multinet_ = esp_mn_handle_from_name(mn_name_);
    multinet_model_data_ = multinet_->create(mn_name_, duration_);
    multinet_->set_det_threshold(multinet_model_data_, threshold_);
    esp_mn_commands_clear();
    for (int i = 0; i < commands_.size(); i++)
    {
        esp_mn_commands_add(i + 1, commands_[i].command.c_str());
    }
    esp_mn_commands_update();

    multinet_->print_active_speech_commands(multinet_model_data_);
    return true;
}

bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    codec_ = codec;
    models_ = models_list;

    // Parse model configuration from index.json
    ParseWakenetModelConfig();

    // Check if we have valid configuration
    if (language_.empty() || commands_.empty()) {
        ESP_LOGE(TAG, "Invalid wake word configuration");
        return false;
    }

    // Find the appropriate multinet model based on language
    const esp_mn_iface_t* multinet_iface = nullptr;
    if (language_ == "en") {
        multinet_iface = &MULTINET_MODEL_EN;
    } else if (language_ == "zh") {
        multinet_iface = &MULTINET_MODEL_ZH;
    } else {
        ESP_LOGE(TAG, "Unsupported language: %s", language_.c_str());
        return false;
    }

    multinet_ = multinet_iface;

    // Create multinet model data
    multinet_model_data_ = multinet_->create();
    if (multinet_model_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Set detection threshold
    multinet_->set_det_threshold(multinet_model_data_, threshold_);

    // Register custom commands
    std::vector<const char*> command_strings;
    for (const auto& command : commands_) {
        command_strings.push_back(command.text.c_str());
    }

    if (!command_strings.empty()) {
        multinet_->set_command_list(multinet_model_data_, 
                                   command_strings.data(), 
                                   command_strings.size());
    }

    ESP_LOGI(TAG, "Custom wake word initialized successfully");
    ESP_LOGI(TAG, "Language: %s, Threshold: %f, Commands: %d", 
             language_.c_str(), threshold_, commands_.size());

    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (!running_ || multinet_model_data_ == nullptr || data.empty())
    {
        return;
    }

    std::vector<int16_t> mono_data;
    const int16_t *input_data = data.data();
    size_t input_size = data.size();

    // Handle stereo to mono conversion if needed (assuming interleaved stereo)
    // If stereo (2 channels), extract left channel
    if (input_size % 2 == 0 && input_size > 1)
    {
        // Assume stereo input, extract left channel
        mono_data.reserve(input_size / 2);
        for (size_t i = 0; i < input_size; i += 2)
        {
            mono_data.push_back(input_data[i]);
        }
        input_data = mono_data.data();
        input_size = mono_data.size();
    }

    size_t chunk_size = multinet_->get_samp_chunksize(multinet_model_data_);

    // Process data in chunks
    for (size_t i = 0; i < input_size; i += chunk_size)
    {
        if (!running_)
        {
            break;
        }

        size_t current_chunk_size = std::min(chunk_size, input_size - i);

        // Run wake word detection
        esp_mn_state_t *state = multinet_->detect(multinet_model_data_, 
                                                  const_cast<int16_t*>(input_data + i));

        if (state->is_waked && state->command_id > 0)
        {
            // Valid wake word detected
            int command_index = state->command_id - 1;
            if (command_index < commands_.size())
            {
                const std::string wake_word = commands_[command_index].text;

                // Store wake word data for encoding
                std::vector<int16_t> wake_data(input_data + i, input_data + i + current_chunk_size);
                StoreWakeWordData(wake_data);

                // Encode stored wake word data
                EncodeWakeWordData();

                // Trigger callback if registered
                if (wake_word_detected_callback_)
                {
                    wake_word_detected_callback_(wake_word);
                }

                // Stop processing until reactivated
                running_ = false;
                break;
            }
        }
        else
        {
            // No wake word detected, just store data for potential future detection
            std::vector<int16_t> chunk_data(input_data + i, input_data + i + current_chunk_size);
            StoreWakeWordData(chunk_data);
        }
    }
}

size_t CustomWakeWord::GetFeedSize()
{
    if (multinet_model_data_ == nullptr)
    {
        return 0;
    }
    return multinet_->get_samp_chunksize(multinet_model_data_);
}

void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t> &data)
{
    // store audio data to wake_word_pcm_
    wake_word_pcm_.push_back(data);
    // keep about 2 seconds of data, detect duration is 30ms (sample_rate == 16000, chunksize == 512)
    while (wake_word_pcm_.size() > 2000 / 30)
    {
        wake_word_pcm_.pop_front();
    }
}

void CustomWakeWord::EncodeWakeWordData()
{
    // Check if we already have a task running or no PCM data to encode
    if (wake_word_encode_task_stack_ != nullptr || wake_word_pcm_.empty()) {
        return;
    }

    // Allocate memory for task stack (4KB should be sufficient)
    wake_word_encode_task_stack_ = static_cast<uint8_t*>(heap_caps_malloc(4096, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
    if (wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for wake word encode task stack");
        return;
    }

    // Allocate memory for encoding buffer (suitable for Opus encoded frames)
    wake_word_encode_task_buffer_ = static_cast<uint8_t*>(heap_caps_malloc(4096, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
    if (wake_word_encode_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for wake word encode task buffer");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return;
    }

    // Create a lambda function for the encoding task
    auto encode_task = [](void* arg) {
        CustomWakeWord* instance = static_cast<CustomWakeWord*>(arg);

        // Initialize Opus encoder with low complexity settings
        OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
        if (encoder == nullptr) {
            ESP_LOGE(TAG, "Failed to create Opus encoder");
            instance->CleanUpEncodeTaskResources();
            vTaskDelete(nullptr);
            return;
        }

        // Set low complexity encoding
        opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
        opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_AUTO));

        // Process all PCM segments
        {
            std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
            for (const auto& pcm_segment : instance->wake_word_pcm_) {
                // Encode the PCM segment
                int frame_size = pcm_segment.size();
                if (frame_size > 0) {
                    int max_data_bytes = 4096; // Size of our buffer
                    int encoded_bytes = opus_encode(encoder, 
                                                  pcm_segment.data(), 
                                                  frame_size, 
                                                  instance->wake_word_encode_task_buffer_, 
                                                  max_data_bytes);

                    if (encoded_bytes > 0) {
                        // Store encoded data
                        std::vector<uint8_t> opus_frame(instance->wake_word_encode_task_buffer_, 
                                                       instance->wake_word_encode_task_buffer_ + encoded_bytes);
                        instance->wake_word_opus_.push_back(opus_frame);
                    } else {
                        ESP_LOGW(TAG, "Opus encoding failed with error: %d", encoded_bytes);
                    }
                }
            }
        }

        // Add termination marker (empty Opus frame to indicate end of stream)
        std::vector<uint8_t> termination_marker;
        {
            std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
            instance->wake_word_opus_.push_back(termination_marker);
        }

        // Signal that encoding is complete and data is available
        instance->wake_word_cv_.notify_all();

        // Cleanup
        opus_encoder_destroy(encoder);
        instance->CleanUpEncodeTaskResources();

        vTaskDelete(nullptr);
    };

    // Create the encoding task
    BaseType_t result = xTaskCreatePinnedToCore(
        reinterpret_cast<TaskFunction_t>(encode_task),
        "WakeWordEncodeTask",
        4096,
        this,
        5,  // Priority
        nullptr,
        1   // Core ID
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
    }
}

// Helper function to clean up task resources (should be added to the class)
void CustomWakeWord::CleanUpEncodeTaskResources()
{
    if (wake_word_encode_task_stack_ != nullptr) {
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    if (wake_word_encode_task_buffer_ != nullptr) {
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }
}

bool CustomWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);
    wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

    std::vector<uint8_t> front_packet = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    // Check for end-of-data sentinel (empty packet)
    if (front_packet.empty()) {
        return false;
    }

    opus.swap(front_packet);
    return true;
}

XL9555::XL9555(i2c_master_bus_handle_t i2c_bus, uint8_t addr) : I2cDevice(i2c_bus, addr)
{
    // Configure all pins of port 0 and port 1 as outputs
    WriteReg(0x06, 0x00); // Configuration register for port 0: 0 = output, 1 = input
    WriteReg(0x07, 0x00); // Configuration register for port 1: 0 = output, 1 = input
}

void SetOutputState(uint8_t bit, uint8_t level)
{
    if ((bit >= 2 && bit <= 7) || (bit >= 8 && bit <= 11)) {
        uint8_t reg_addr;
        uint8_t port_bit;

        if (bit < 8) {
            // Port 0
            reg_addr = 0x02;       // Output register for Port 0
            port_bit = bit;
        } else {
            // Port 1
            reg_addr = 0x03;       // Output register for Port 1
            port_bit = bit - 8;
        }

        // Read current register value
        uint8_t current_value = ReadReg(reg_addr);

        // Update the specific bit
        if (level) {
            current_value |= (1 << port_bit);
        } else {
            current_value &= ~(1 << port_bit);
        }

        // Write updated value back
        WriteReg(reg_addr, current_value);
    }
}

void InitializeI2c()
{
    // Initialize I2C master bus configuration
    i2c_master_bus_config_t i2c_bus_cfg = {};
    i2c_bus_cfg.clk_source = I2C_CLK_SRC_DEFAULT;
    i2c_bus_cfg.scl_io_num = I2C_SCL_PIN;
    i2c_bus_cfg.sda_io_num = I2C_SDA_PIN;
    i2c_bus_cfg.glitch_ignore_cnt = 7;
    i2c_bus_cfg.flags.enable_internal_pullup = true;

    // Create I2C master bus
    ESP_ERROR_CHECK(i2c_new_master_bus(&i2c_bus_cfg, &i2c_bus_));

    // Instantiate and initialize XL9555 I/O expander at address 0x20
    xl9555_ = new XL9555(i2c_bus_, 0x20);
}

void InitializeSpi()
{
    spi_bus_config_t buscfg = {};
    buscfg.mosi_io_num = LCD_MOSI_PIN;
