void InitializeCamera()
{
    // Configure camera power and reset pins through XL9555 I/O expander
    // PWDN pin configuration (active low)
    xl9555_->SetOutputState(CAM_PIN_PWDN, 1); // Power down initially
    vTaskDelay(pdMS_TO_TICKS(10));

    // Reset pin configuration
    xl9555_->SetOutputState(CAM_PIN_RESET, 0); // Reset active low
    vTaskDelay(pdMS_TO_TICKS(10));

    // Power up sequence
    xl9555_->SetOutputState(CAM_PIN_PWDN, 0); // Power up camera
    vTaskDelay(pdMS_TO_TICKS(10));

    // Release reset
    xl9555_->SetOutputState(CAM_PIN_RESET, 1);
    vTaskDelay(pdMS_TO_TICKS(10));

    // Define DVP pin configuration
    esp_video_dvp_pin_config_t dvp_pin_config = {
        .yuv_pins = {
            [0] = CAM_PIN_D0,
            [1] = CAM_PIN_D1,
            [2] = CAM_PIN_D2,
            [3] = CAM_PIN_D3,
            [4] = CAM_PIN_D4,
            [5] = CAM_PIN_D5,
            [6] = CAM_PIN_D6,
            [7] = CAM_PIN_D7,
        },
        .vsync_io = CAM_PIN_VSYNC,
        .de_io = CAM_PIN_HREF,
        .pclk_io = CAM_PIN_PCLK,
        .xclk_io = CAM_PIN_XCLK,
    };

    // SCCB/I2C configuration
    esp_video_init_sccb_config_t sccb_config = {
        .init_sccb = true,
        .i2c_config = {
            .port = 1,
            .scl_pin = CAM_PIN_SIOC,
            .sda_pin = CAM_PIN_SIOD,
        },
        .freq = 100000,
    };

    // DVP configuration
    esp_video_init_dvp_config_t dvp_config = {
        .sccb_config = sccb_config,
        .reset_pin = CAM_PIN_RESET, // Controlled via XL9555
        .pwdn_pin = CAM_PIN_PWDN,   // Controlled via XL9555
        .dvp_pin = dvp_pin_config,
        .xclk_freq = 20000000,
