void ReceiveWifiCredentialsFromAudio(Application *app, WifiManager *wifi_manager, Display *display, size_t sample_rate)
{
    // AFSK parameters for Bell 202 standard (1200/2200 Hz)
    const size_t kMarkFrequency = 1200;   // Mark frequency (1)
    const size_t kSpaceFrequency = 2200;  // Space frequency (0)
    const size_t kBitRate = 1200;         // Bit rate
    const size_t kWindowSize = 128;       // Window size for Goertzel algorithm
    const float kThreshold = 0.5f;        // Probability threshold for bit detection

    // Initialize audio signal processor
    AudioSignalProcessor processor(sample_rate, kMarkFrequency, kSpaceFrequency, kBitRate, kWindowSize);

    // Initialize audio data buffer
    AudioDataBuffer data_buffer;

    // Buffer for audio samples
    std::vector<float> audio_buffer;
    audio_buffer.reserve(1024);

    ESP_LOGI(kLogTag, "Starting audio WiFi credential reception");
    display->ShowMessage("Listening for WiFi credentials...");

    // Main processing loop
    while (app->IsInConfigMode())
    {
        // Read audio samples (implementation depends on your audio input method)
        // This is a placeholder - you'll need to replace with actual audio capture code
        std::vector<int16_t> raw_samples;

        // Simulate reading audio data - replace with actual audio input implementation
        // For example, if using ADC or I2S:
        // raw_samples = app->ReadAudioSamples(512);

        if (!raw_samples.empty())
        {
            // Convert stereo to mono if needed and normalize to float
            std::vector<float> mono_samples;
            mono_samples.reserve(raw_samples.size());

            for (size_t i = 0; i < raw_samples.size(); i++)
            {
                // Convert int16 to float (-1.0 to 1.0)
                mono_samples.push_back(static_cast<float>(raw_samples[i]) / 32768.0f);
            }

            // Downsample if necessary (this is simplified - actual implementation may vary)
            std::vector<float> processed_samples = processor.ProcessAudioSamples(mono_samples);

            // Process the probability data
            if (!processed_samples.empty())
            {
                bool data_received = data_buffer.ProcessProbabilityData(processed_samples, kThreshold);

                if (data_received)
                {
                    std::string received_data = data_buffer.decoded_text;

                    ESP_LOGI(kLogTag, "Received data: %s", received_data.c_str());

                    // Parse WiFi credentials (assuming format: "SSID:PASSWORD")
                    size_t colon_pos = received_data.find(':');
                    if (colon_pos != std::string::npos)
                    {
                        std::string ssid = received_data.substr(0, colon_pos);
                        std::string password = received_data.substr(colon_pos + 1);

                        ESP_LOGI(kLogTag, "Extracted SSID: %s, Password: %s", ssid.c_str(), password.c_str());

                        // Update display
                        display->ShowMessage("Connecting to WiFi...");

                        // Connect to WiFi network
                        if (wifi_manager->ConnectToNetwork(ssid, password))
                        {
                            ESP_LOGI(kLogTag, "Successfully connected to WiFi network");
                            display->ShowMessage("WiFi Connected!");

                            // Exit configuration mode
                            app->ExitConfigMode();
                            break;
                        }
                        else
                        {
                            ESP_LOGE(kLogTag, "Failed to connect to WiFi network");
                            display->ShowMessage("Connection failed. Retrying...");
                        }
                    }
                    else
                    {
                        ESP_LOGW(kLogTag, "Invalid data format received: %s", received_data.c_str());
                        display->ShowMessage("Invalid data received");
                    }
                }
            }
        }

        // Small delay to prevent busy waiting
        vTaskDelay(pdMS_TO_TICKS(10));
    }

    ESP_LOGI(kLogTag, "Finished audio WiFi credential reception");
}

FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : window_size_(window_size)
{
    float omega = 2.0f * M_PI * frequency;
    filter_coefficient_ = 2.0f * std::cos(omega);
    cos_coefficient_ = std::cos(omega);
    sin_coefficient_ = std::sin(omega);

    // Initialize state buffer with two zeros
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::Reset()
{
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::ProcessSample(float sample)
{
    // Ensure state buffer has capacity for at least 2 elements
    if (state_buffer_.size() < 2) {
        // Initialize buffer with zeros if empty
        while (state_buffer_.size() < 2) {
            state_buffer_.push_back(0.0f);
        }
    }

    // Get the two previous states
    float s_minus_2 = state_buffer_.front();  // S[-2]
    state_buffer_.pop_front();
    float s_minus_1 = state_buffer_.front();  // S[-1]
    state_buffer_.pop_front();

    // Apply the second-order IIR filter difference equation
    // S[n] = x[n] + 2*cos(ω)*S[n-1] - S[n-2]
    float s_current = sample + 2.0f * cos_coefficient_ * s_minus_1 - s_minus_2;

    // Update the state buffer with the new values
    state_buffer_.push_back(s_minus_1);   // Put S[-1] back as new S[-2]
    state_buffer_.push_back(s_current);   // Add new S[0]
}

float FrequencyDetector::GetAmplitude() const
{
    // Check if we have enough samples in the buffer
    if (state_buffer_.size() < 2)
    {
        return 0.0f;
    }

    // Get the last two states from the buffer
    auto it = state_buffer_.rbegin();
    float s_current = *it;  // S[0] - most recent
    ++it;
    float s_minus_1 = *it;  // S[-1] - previous sample

    // Calculate real and imaginary parts using Goertzel algorithm
    // Real part: S[0] - S[-1] * cos(ω)
    float real_part = s_current - s_minus_1 * cos_coefficient_;

    // Imaginary part: S[-1] * sin(ω)
    float imaginary_part = s_minus_1 * sin_coefficient_;

    // Calculate amplitude as magnitude of complex number
    // Amplitude = sqrt(real² + imaginary²) / (N/2)
    // where N is the window size
    float magnitude_squared = real_part * real_part + imaginary_part * imaginary_part;
    float amplitude = std::sqrt(magnitude_squared) / (static_cast<float>(window_size_) * 0.5f);

    return amplitude;
}

AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency,
                                         size_t bit_rate, size_t window_size)
    : sample_rate_(sample_rate)
    , bit_rate_(bit_rate)
    , window_size_(window_size)
    , output_sample_count_(0)
{
    // Calculate samples per bit
    samples_per_bit_ = sample_rate_ / bit_rate_;

    // Validate that sample rate is divisible by bit rate
    if (sample_rate_ % bit_rate_ != 0) {
        ESP_LOGW(kLogTag, "Sample rate (%d) is not divisible by bit rate (%d)", 
                 static_cast<int>(sample_rate_), static_cast<int>(bit_rate_));
    }

    // Create frequency detectors for mark and space frequencies
    mark_detector_ = std::make_unique<FrequencyDetector>(
        static_cast<float>(mark_frequency) / static_cast<float>(sample_rate_) * 2.0f, 
        window_size_
    );

    space_detector_ = std::make_unique<FrequencyDetector>(
        static_cast<float>(space_frequency) / static_cast<float>(sample_rate_) * 2.0f, 
        window_size_
    );

    // Calculate input buffer size based on window size
    input_buffer_size_ = window_size_;
    input_buffer_.reserve(input_buffer_size_);
}

std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float>& samples)
{
    std::vector<float> result;
    result.reserve(samples.size() / kWindowSize); // Reserve approximate size

    for (float sample : samples)
    {
        // Process sample with both detectors
        mark_detector_->ProcessSample(sample);
        space_detector_->ProcessSample(sample);

        // Increment output sample counter
        output_sample_count_++;

        // When we have enough samples for a window, calculate probability
        if (output_sample_count_ >= kWindowSize)
        {
            // Get amplitudes from both detectors
            float mark_amplitude = mark_detector_->GetAmplitude();
            float space_amplitude = space_detector_->GetAmplitude();

            // Calculate probability of mark tone presence
            float mark_probability = mark_amplitude / 
                (space_amplitude + mark_amplitude + std::numeric_limits<float>::epsilon());

            result.push_back(mark_probability);

            // Reset detector windows
            mark_detector_->Reset();
            space_detector_->Reset();
            output_sample_count_ = 0; // Reset output counter
        }
    }

    return result;
}

AudioDataBuffer::AudioDataBuffer()
    : current_state_(DataReceptionState::kInactive),
      start_of_transmission_(kDefaultStartTransmissionPattern),
      end_of_transmission_(kDefaultEndTransmissionPattern),
      enable_checksum_validation_(true)
{
    identifier_buffer_size_ = std::max(start_of_transmission_.size(), end_of_transmission_.size());
    max_bit_buffer_size_ = 776; // Preset bit buffer size, 776 bits = (32 + 1 + 63 + 1) * 8 = 776

    bit_buffer_.reserve(max_bit_buffer_size_);
}

AudioDataBuffer::AudioDataBuffer(size_t max_byte_size, const std::vector<uint8_t> &start_identifier,
                                 const std::vector<uint8_t> &end_identifier, bool enable_checksum)
    : current_state_(DataReceptionState::kInactive),
      start_of_transmission_(start_identifier),
      end_of_transmission_(end_identifier),
      enable_checksum_validation_(enable_checksum)
{
    identifier_buffer_size_ = std::max(start_of_transmission_.size(), end_of_transmission_.size());
    max_bit_buffer_size_ = max_byte_size * 8; // Convert bytes to bits

    bit_buffer_.reserve(max_bit_buffer_size_);
}

uint8_t AudioDataBuffer::CalculateChecksum(const std::string &text)
{
    uint8_t checksum = 0;
    for (char character : text)
    {
        checksum += static_cast<uint8_t>(character);
    }
    return checksum;
}

void AudioDataBuffer::ClearBuffers()
{
    identifier_buffer_.clear();
    bit_buffer_.clear();
}

bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold)
{
    bool data_complete = false;

    for (float probability : probabilities)
    {
        uint8_t bit = (probability >= threshold) ? 1 : 0;

        switch (current_state_)
        {
        case DataReceptionState::kInactive:
            // Collect bits in identifier buffer to detect start pattern
            if (identifier_buffer_.size() < identifier_buffer_size_)
            {
                identifier_buffer_.push_back(bit);
            }
            else
            {
                // Shift the buffer and add new bit
                identifier_buffer_.pop_front();
                identifier_buffer_.push_back(bit);
            }

            // Check if start transmission pattern is detected
            if (identifier_buffer_.size() == start_of_transmission_.size() &&
                std::equal(identifier_buffer_.begin(), identifier_buffer_.end(), start_of_transmission_.begin()))
            {
                current_state_ = DataReceptionState::kWaitingForData;
                ClearBuffers(); // Clear buffers for actual data reception
            }
            break;

        case DataReceptionState::kWaitingForData:
            // Collect actual data bits
            if (bit_buffer_.size() < max_bit_buffer_size_)
            {
                bit_buffer_.push_back(bit);
            }

            // Check if we have enough bits to form the end transmission pattern
            if (bit_buffer_.size() >= end_of_transmission_.size())
            {
                // Check if the last bits match the end transmission pattern
                bool end_pattern_matched = true;
                auto bit_it = bit_buffer_.end() - end_of_transmission_.size();
                for (size_t i = 0; i < end_of_transmission_.size(); ++i, ++bit_it)
                {
                    if (*bit_it != end_of_transmission_[i])
                    {
                        end_pattern_matched = false;
                        break;
                    }
                }

                if (end_pattern_matched)
                {
                    current_state_ = DataReceptionState::kReceivingComplete;
                    // Remove the end transmission pattern from bit buffer
                    bit_buffer_.resize(bit_buffer_.size() - end_of_transmission_.size());
                }
            }

            // Check if buffer is full
            if (bit_buffer_.size() >= max_bit_buffer_size_)
            {
                current_state_ = DataReceptionState::kReceivingComplete;
            }
            break;

        case DataReceptionState::kReceivingComplete:
            // Process the received data
            if (!bit_buffer_.empty())
            {
                // Convert bits to bytes
                std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);

                if (!bytes.empty())
                {
                    // Extract payload (excluding checksum if enabled)
                    size_t payload_size = bytes.size();
                    if (enable_checksum_validation_ && payload_size > 1)
                    {
                        // Last byte is checksum
                        uint8_t received_checksum = bytes.back();
                        std::string payload(bytes.begin(), bytes.end() - 1);

                        // Calculate expected checksum
                        uint8_t calculated_checksum = CalculateChecksum(payload);

                        if (received_checksum == calculated_checksum)
                        {
                            decoded_text = std::move(payload);
                            data_complete = true;
                        }
                        else
                        {
                            ESP_LOGW(kLogTag, "Checksum validation failed");
                        }
                    }
                    else
                    {
                        // No checksum validation
                        decoded_text = std::string(bytes.begin(), bytes.end());
                        data_complete = true;
                    }
                }
            }

            // Reset to inactive state for next transmission
            current_state_ = DataReceptionState::kInactive;
            ClearBuffers();
            break;
        }
    }

    return data_complete;
}

std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
{
    if (bits.empty()) {
        return std::vector<uint8_t>();
    }

    // Calculate the number of complete bytes we can form
    size_t num_bytes = bits.size() / 8;
    std::vector<uint8_t> bytes;
    bytes.reserve(num_bytes);

    // Process each group of 8 bits
    for (size_t i = 0; i < num_bytes; ++i) {
        uint8_t byte_value = 0;

        // Process 8 bits for this byte (MSB first)
        for (size_t bit_pos = 0; bit_pos < 8; ++bit_pos) {
            size_t bit_index = i * 8 + bit_pos;
            if (bit_index < bits.size() && bits[bit_index] == 1) {
                // Set the corresponding bit position (MSB first order)
                byte_value |= (1 << (7 - bit_pos));
            }
        }

        bytes.push_back(byte_value);
    }

    return bytes;
}

Backlight::Backlight()
{
    brightness_ = 0;
    target_brightness_ = 0;
    step_ = 0;
    transition_timer_ = nullptr;

    // Create timer for brightness transitions
    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            static_cast<Backlight*>(arg)->OnTransitionTimer();
        },
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "backlight_transition",
        .skip_unhandled_events = true
    };

    ESP_ERROR_CHECK(esp_timer_create(&timer_args, &transition_timer_));
}

Backlight::~Backlight()
{
    if (transition_timer_ != nullptr)
    {
        esp_timer_stop(transition_timer_);
        esp_timer_delete(transition_timer_);
        transition_timer_ = nullptr;
    }
}

void Backlight::RestoreBrightness()
{
    Settings settings("display", true);
    int32_t brightness = settings.GetInt("brightness", 0);

    // If brightness is zero or invalid, set to default minimum of 10
    if (brightness <= 0)
    {
        brightness = 10;
    }

    // Apply the restored brightness without saving back to settings
    SetBrightness(static_cast<uint8_t>(brightness), false);
}

void Backlight::SetBrightness(uint8_t brightness, bool permanent)
{
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100)
        brightness = 100;

    // No update required if same as current target
    if (brightness == target_brightness_)
        return;

    // Save brightness permanently if requested
    if (permanent)
    {
        Settings settings("display");
        settings.SetInt("brightness", brightness);
        settings.Save();
    }

    // Update target brightness
    target_brightness_ = brightness;

    // Determine step size/direction for smooth transition
    const int kTransitionSteps = 10; // Number of steps for fade effect
    int diff = static_cast<int>(target_brightness_) - static_cast<int>(brightness_);

    if (diff != 0)
    {
        step_ = (diff > 0) ? ((diff + kTransitionSteps - 1) / kTransitionSteps)
                           : ((diff - kTransitionSteps + 1) / kTransitionSteps);

        // Ensure minimum step of ±1 unless already at target
        if (step_ == 0 && diff != 0)
            step_ = (diff > 0) ? 1 : -1;
    }
    else
    {
        step_ = 0;
    }

    // Restart the timer for smooth transition
    esp_timer_stop(transition_timer_);
    esp_timer_start_periodic(transition_timer_, 30000); // 30ms interval
}

void Backlight::OnTransitionTimer()
{
    if (brightness_ == target_brightness_)
    {
        esp_timer_stop(transition_timer_);
        return;
    }

    brightness_ += step_;

    SetBrightnessImpl(brightness_);

    if (brightness_ == target_brightness_)
    {
        esp_timer_stop(transition_timer_);
    }
}

