        .timer_sel = LEDC_TIMER_0,
        .duty = 0,  // Start with 0% duty cycle
        .hpoint = 0,
        .flags = {
            .output_invert = output_invert ? 1 : 0,  // Set inversion flag
        }
    };
    ESP_ERROR_CHECK(ledc_channel_config(&ledc_channel));
}

void PwmBacklight::SetBrightnessImpl(uint8_t brightness)
{
    // Calculate 10-bit duty value from percentage (0-100 -> 0-1023)
    uint32_t duty = (static_cast<uint32_t>(brightness) * 1023) / 100;

    // Update the LEDC channel duty cycle
    ledc_set_duty_and_update(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty, 0);
}

Board::Board()
{
    // Try to load existing UUID from settings
    uuid_ = Settings::GetInstance().GetString("device.uuid", "");

    // If no UUID exists, generate a new one and save it
    if (uuid_.empty()) {
        uuid_ = GenerateUuid();
        Settings::GetInstance().SetString("device.uuid", uuid_);
        Settings::GetInstance().Save();
    }
}

std::string Board::GenerateUuid()
{
    uint8_t uuid[16];

    // Generate 16 random bytes using ESP32 hardware random number generator
    for (int i = 0; i < 16; i++) {
        uuid[i] = esp_random() & 0xFF;
    }

    // Set the version to 4 (UUIDv4)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;  // 0100xxxx

    // Set the variant to RFC 4122 (bit 6 = 1, bit 7 = 0)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;  // 10xxxxxx

    // Format as hexadecimal string with hyphens
    char uuid_str[37];  // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

