std::string Board::GetSystemInfoJson()
{
    std::string json = "{";

    // Hardware info
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    char mac_str[18];
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    json += "\"hardware\":{";
    json += "\"chip_model\":\"" + std::string(ESP_CHIP_MODEL_STR(chip_info.model)) + "\",";
    json += "\"cores\":" + std::to_string(chip_info.cores) + ",";
    json += "\"revision\":" + std::to_string(chip_info.revision) + ",";
    json += "\"flash_size\":" + std::to_string(esp_flash_get_size(nullptr) / (1024 * 1024)) + ",";
    json += "\"mac_address\":\"" + std::string(mac_str) + "\"";
    json += "},";

    // Application metadata
    json += "\"application\":{";
    json += "\"name\":\"" + std::string(APP_PROJECT_NAME) + "\",";
    json += "\"version\":\"" + std::string(APP_VERSION) + "\",";
    json += "\"compile_time\":\"" + std::string(__DATE__ " " __TIME__) + "\"";
    json += "},";

    // Partition info
    const esp_partition_t* running = esp_ota_get_running_partition();
    json += "\"partition\":{";
    if (running) {
        json += "\"label\":\"" + std::string(running->label) + "\",";
        json += "\"address\":" + std::to_string(running->address) + ",";
        json += "\"size\":" + std::to_string(running->size);
    } else {
        json += "\"error\":\"unknown\"";
    }
    json += "},";

    // Runtime info
    json += "\"runtime\":{";
    json += "\"min_free_heap\":" + std::to_string(esp_get_minimum_free_heap_size()) + ",";
    json += "\"uuid\":\"" + uuid_ + "\"";
    json += "}";

    json += "}";
    return json;
}

