{
    // Initialize the connection timeout timer
    esp_timer_create_args_t timer_conf = {};
    timer_conf.callback = OnWifiConnectTimeout;
    timer_conf.arg = this;
    timer_conf.name = "wifi_connect_timeout";

    esp_err_t err = esp_timer_create(&timer_conf, &connect_timer_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create WiFi connect timeout timer: %s", esp_err_to_name(err));
        connect_timer_ = nullptr;
    }
}

