void WifiBoard::StartNetwork()
{
    auto &wifi_manager = WifiManager::GetInstance();

    // Initialize WiFi manager with board-specific settings
    wifi_manager.SetApSsidPrefix("XiaoZhi-");
    wifi_manager.SetLanguage(Lang::GetCurrentLanguage());

    // Set up unified event callback for all WiFi events
    wifi_manager.SetEventCallback([this](NetworkEvent event, const std::string &data) {
        this->OnNetworkEvent(event, data);
    });

    // Attempt to connect to WiFi or enter config mode
    TryWifiConnect();
}

void WifiBoard::TryWifiConnect()
{
    auto &wifi_manager = WifiManager::GetInstance();

    // Check if we have stored SSID credentials
    if (!wifi_manager.HasStoredSsid())
    {
        ESP_LOGI(TAG, "No stored WiFi credentials found, entering config mode");
        // Brief delay before entering config mode
        vTaskDelay(pdMS_TO_TICKS(1000));
        StartWifiConfigMode();
        return;
    }

    ESP_LOGI(TAG, "Attempting to connect to stored WiFi network");

    // Start connection timeout timer
    esp_timer_stop(connect_timer_);
    esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000);

    // Start WiFi station connection
    wifi_manager.StartStation();
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    switch (event)
    {
    case NetworkEvent::Scanning:
        ESP_LOGI(TAG, "Scanning for networks");
        break;

    case NetworkEvent::Connecting:
        ESP_LOGI(TAG, "Connecting to SSID: %s", data.c_str());
        // Stop the connection timeout timer as we're now connecting
        esp_timer_stop(connect_timer_);
        break;

    case NetworkEvent::Connected:
        ESP_LOGI(TAG, "WiFi connected to SSID: %s", data.c_str());
        // Stop the connection timeout timer
        esp_timer_stop(connect_timer_);

        // No longer in config mode
        in_config_mode_ = false;

        // Release provisioning resources if we were in config mode
        if (WifiManager::GetInstance().IsConfigMode())
        {
            WifiManager::GetInstance().StopConfigAp();
        }

        // Update device state
        Application::GetInstance().SetDeviceState(kDeviceStateIdle);
        break;

    case NetworkEvent::Disconnected:
        ESP_LOGI(TAG, "WiFi disconnected");
        // If we were in config mode, stay in config mode
        // Otherwise, we might want to try reconnecting
        if (!in_config_mode_)
        {
            // Could trigger a reconnection attempt here if needed
        }
        break;

    case NetworkEvent::WifiConfigModeEnter:
        ESP_LOGI(TAG, "Entered WiFi config mode");
        in_config_mode_ = true;
        Application::GetInstance().SetDeviceState(kDeviceStateWifiConfiguring);
        break;

    case NetworkEvent::WifiConfigModeExit:
        ESP_LOGI(TAG, "Exited WiFi config mode");
        in_config_mode_ = false;

        // Stop any ongoing connection attempt
        esp_timer_stop(connect_timer_);

        // Try to connect again after exiting config mode
        TryWifiConnect();

        // Update device state
        Application::GetInstance().SetDeviceState(kDeviceStateIdle);
        break;
    }

    // Notify external callback if set
    if (network_event_callback_)
    {
        network_event_callback_(event, data);
    }
}

void WifiBoard::OnWifiConnectTimeout(void *arg)
{
    auto *board = static_cast<WifiBoard *>(arg);
    ESP_LOGW(TAG, "WiFi connection timeout, entering config mode");

    WifiManager::GetInstance().StopStation();
    board->StartWifiConfigMode();
}

void WifiBoard::StartWifiConfigMode()
{
    ESP_LOGI(TAG, "Entering WiFi configuration mode");

    // Set device state to configuring
    Application::GetInstance().SetDeviceState(kDeviceStateConfiguring);

    // Show notification about entering config mode
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_ACTIVE);

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Bluetooth Low Energy provisioning via Blufi
    ESP_LOGI(TAG, "Starting Blufi provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::BLUFI_PROVISIONING_STARTED);
    Blufi::GetInstance().init();
    WifiManager::GetInstance().StartBlufiConfig();
#elif defined(CONFIG_USE_ACOUSTIC_WIFI_PROVISIONING)
    // Acoustic provisioning through audio input
    ESP_LOGI(TAG, "Starting acoustic provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::ACOUSTIC_PROVISIONING_STARTED);
    // Start AFSK demodulator for acoustic provisioning
    AfskDemod::GetInstance().Start();
    WifiManager::GetInstance().StartAcousticConfig();
#else
    // Default hotspot-based configuration
    ESP_LOGI(TAG, "Starting hotspot-based configuration");
    GetDisplay()->ShowNotification(Lang::Strings::HOTSPOT_CONFIG_STARTED);
    WifiManager::GetInstance().StartAccessPoint();
#endif
}

void WifiBoard::EnterWifiConfigMode()
{
    // Check if we're already in config mode to prevent conflicts
    if (IsInWifiConfigMode()) {
        ESP_LOGW(TAG, "Already in WiFi config mode");
        return;
    }

    ESP_LOGI(TAG, "Entering WiFi config mode");

    // Gracefully shut down any active network connections
    auto& wifi_manager = WifiManager::GetInstance();

    // Stop any ongoing station connection attempts
    if (wifi_manager.IsStationActive()) {
        wifi_manager.StopStation();
    }

    // Stop the connection timeout timer if running
    if (connect_timer_) {
        esp_timer_stop(connect_timer_);
    }

    // Reset any active audio/communication processes
    // Stop AFSK demodulation if active
    AfskDemod::GetInstance().Stop();

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Make sure Blufi is properly deinitialized
    Blufi::GetInstance().deinit();
#endif

    // Display notification about entering config mode
    Application::GetInstance().Alert(
        Lang::Strings::WIFI_CONFIG_MODE, 
        Lang::Strings::WIFI_CONFIG_MODE_DESC, 
        "gear", 
        Lang::Sounds::OGG_WIFICONFIG
    );

    // Give some time for the alert to be displayed
    vTaskDelay(pdMS_TO_TICKS(500));

    // Start the WiFi configuration mode
    StartWifiConfigMode();
}

