const char *WifiBoard::GetNetworkStateIcon()
{
    auto &wifi = WifiManager::GetInstance();

    // Check if in config mode
    if (wifi.IsConfigMode()) {
        return "wifi_config";
    }

    // Check if not connected
    if (!wifi.IsConnected()) {
        return "wifi_off";
    }

    // Determine signal strength based on RSSI
    int rssi = wifi.GetRssi();
    if (rssi >= -60) {
        return "wifi_strong";
    } else if (rssi >= -70) {
        return "wifi_medium";
    } else {
        return "wifi_weak";
    }
}

std::string WifiBoard::GetBoardJson()
{
    auto &wifi = WifiManager::GetInstance();
    auto root = cJSON_CreateObject();

    // Add basic board information
    cJSON_AddStringToObject(root, "type", "wifi");
    cJSON_AddStringToObject(root, "name", SystemInfo::GetBoardName().c_str());
    cJSON_AddStringToObject(root, "mac", wifi.GetMacAddress().c_str());

    // Add Wi-Fi details only when not in config mode
    if (!wifi.IsConfigMode()) {
        auto wifi_obj = cJSON_CreateObject();
        cJSON_AddStringToObject(wifi_obj, "ssid", wifi.GetSsid().c_str());
        cJSON_AddNumberToObject(wifi_obj, "rssi", wifi.GetRssi());
        cJSON_AddNumberToObject(wifi_obj, "channel", wifi.GetChannel());
        cJSON_AddStringToObject(wifi_obj, "ip", wifi.GetIpAddress().c_str());
        cJSON_AddItemToObject(root, "wifi", wifi_obj);
    }

    char *json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str);
    cJSON_free(json_str);
    cJSON_Delete(root);

    return result;
}

void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    auto& wifi_manager = WifiManager::GetInstance();

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            // Enable maximum power saving - this typically means longer sleep intervals
            wifi_manager.SetPowerSaveMode(WIFI_PS_MIN_MODEM);
            break;

        case PowerSaveLevel::BALANCED:
            // Enable balanced power saving - moderate sleep intervals
            wifi_manager.SetPowerSaveMode(WIFI_PS_MAX_MODEM);
            break;

        case PowerSaveLevel::PERFORMANCE:
            // Disable power saving for maximum performance
            wifi_manager.SetPowerSaveMode(WIFI_PS_NONE);
            break;

        default:
            // Default to balanced mode for unknown levels
            wifi_manager.SetPowerSaveMode(WIFI_PS_MAX_MODEM);
            break;
    }
}

